class Solution {
    long long modPow(long long a, long long e, int mod) {
        long long r = 1; a %= mod;
        while (e) { if (e & 1) r = r * a % mod; a = a * a % mod; e >>= 1; }
        return r;
    }
public:
    int superPow(int a, vector<int>& b) {
        const int mod = 1337;
        long long ans = 1;
        a %= mod;
        for (int d : b) ans = modPow(ans, 10, mod) * modPow(a, d, mod) % mod;
        return (int)ans;
    }
};

